import  {useState, useEffect} from 'react';
import { useParams } from 'react-router-dom';


const Details = () =>{
    let{userid} = useParams();
    // it use to capture value from browser url in react
    let[name, pickName] = useState("");
    let[email, pickemail] = useState("");
    let[mobile, pickmobile] = useState("");
    let[date, pickdate] = useState("");
   

    const getuserinfo = () =>{
        let url = "http://localhost:3333/user/"+userid;
        fetch(url)
        .then(response => response.json())
        .then(empinfo =>{
            pickName(empinfo.name);
            pickemail(empinfo.email);
            pickmobile(empinfo.mobile);
            pickdate(empinfo.date);
        })
    }

     useEffect(() =>{
        getuserinfo();
     },[1]);

    const back = () =>{
        window.location.href = "#/";
       };
     
       

   return(
     <div className="container mt-4">
        <div className="row">
            <div className="col-lg-3"> </div>
            <div className="col-lg-6 text-center w-50 border bg-secondary text-white p-5"> 
              <h1 className=" text-primary"> User's Details </h1>

                    <div className= "mb-4">
                        <label> User's Name : {name}</label>  
                    </div>

                    <div className= "mb-4">
                    <label> User's Email : {email}</label>  
                    </div>

                    <div className= "mb-4">
                    <label> User's Mobile : {mobile}</label>   
                    </div>

                    <div className= "mb-4">
                    <label> Last modified: {date}</label>  
                    </div>

                    <div className="text-center">
                    <button className="btn btn-danger" onClick={back}> Back </button>
                    </div>
             </div> 

             <div className="col-lg-3"> </div>
             </div> 
        </div>  
   )
}


export default Details;
